"""
Sleep IMU data processing using BioPsyKit.
Computes sleep_onset, wake_onset, and total_sleep_duration from IMU acceleration data.
"""

import json
import os
import warnings

import numpy as np
import pandas as pd

warnings.filterwarnings("ignore")

# ── 1. Load data ──────────────────────────────────────────────────────────────
data_path = "benchmark/datasets/sleep_imu_data/sleep_data.pkl"
df = pd.read_pickle(data_path)

# Inspect the index — it should be a DatetimeIndex (timezone-aware)
# Round-2 failure: OutOfBoundsDatetime when trying unit='us' conversion.
# Strategy: ensure index is already DatetimeIndex; if it's object dtype (strings),
# parse without unit kwarg to let pandas auto-detect the format.
if not isinstance(df.index, pd.DatetimeIndex):
    # Try converting from strings; avoid unit='us' which caused round-2 crash
    df.index = pd.to_datetime(df.index, utc=True)
else:
    # Already DatetimeIndex — ensure it is UTC-aware or has tz info; keep as-is
    if df.index.tz is None:
        df.index = df.index.tz_localize("UTC")

# Sort by time to be safe
df = df.sort_index()

# ── 2. Compute sampling rate from timestamp differences ───────────────────────
# median delta in seconds to be robust to gaps
time_diffs = df.index.to_series().diff().dropna().dt.total_seconds()
median_diff = float(time_diffs.median())
sampling_rate = round(1.0 / median_diff) if median_diff > 0 else 204  # ~204 Hz typical wrist IMU

# ── 3. Extract acceleration columns ──────────────────────────────────────────
# BioPsyKit expects a DataFrame with acc_x, acc_y, acc_z columns
acc_cols = [c for c in df.columns if c.startswith("acc_")]
if len(acc_cols) < 3:
    # fallback: look for any column containing 'acc'
    acc_cols = [c for c in df.columns if "acc" in c.lower()]

acc_df = df[acc_cols].copy()
# Rename to expected convention if needed
rename_map = {}
for col in acc_df.columns:
    lower = col.lower()
    if "acc_x" in lower or lower == "acc_x":
        rename_map[col] = "acc_x"
    elif "acc_y" in lower or lower == "acc_y":
        rename_map[col] = "acc_y"
    elif "acc_z" in lower or lower == "acc_z":
        rename_map[col] = "acc_z"
if rename_map:
    acc_df = acc_df.rename(columns=rename_map)

# ── 4. Run BioPsyKit sleep pipeline ──────────────────────────────────────────
from biopsykit.sleep import sleep_processing_pipeline as spp  # noqa: E402

# predict_pipeline_acceleration requires sampling_rate (round-1 fix)
sleep_results = spp.predict_pipeline_acceleration(acc_df, sampling_rate=sampling_rate)

# ── 5. Extract endpoints ──────────────────────────────────────────────────────
# sleep_results is typically a dict with keys like 'sleep_onset', 'wake_onset',
# 'sleep_onset_time', 'wake_onset_time', 'total_sleep_duration', etc.
# Normalise to scalar / string values safe for JSON serialisation.

def _to_serialisable(val):
    """Convert timestamps, timedeltas, numpy scalars to JSON-friendly types."""
    if isinstance(val, pd.Timestamp):
        return val.isoformat()
    if isinstance(val, pd.Timedelta):
        return val.total_seconds()
    if isinstance(val, np.integer):
        return int(val)
    if isinstance(val, np.floating):
        return float(val)
    if isinstance(val, (int, float, str, bool, type(None))):
        return val
    # Last resort: str
    return str(val)


# Helper to look up a key case-insensitively across result dict
def _get(d, *keys):
    for k in keys:
        if k in d:
            return d[k]
    # case-insensitive fallback
    lk = {key.lower(): v for key, v in d.items()}
    for k in keys:
        if k.lower() in lk:
            return lk[k.lower()]
    return None


sleep_onset_val = _get(
    sleep_results, "sleep_onset", "sleep_onset_time", "SleepOnset"
)
wake_onset_val = _get(
    sleep_results, "wake_onset", "wake_onset_time", "WakeOnset"
)
total_sleep_val = _get(
    sleep_results,
    "total_sleep_duration",
    "TotalSleepDuration",
    "sleep_duration",
)

# Convert total_sleep_duration: if it's a Timedelta keep seconds; if already number keep it;
# if it's a Timestamp something went wrong — stringify it
output = {
    "sleep_onset": _to_serialisable(sleep_onset_val),
    "wake_onset": _to_serialisable(wake_onset_val),
    "total_sleep_duration": _to_serialisable(total_sleep_val),
}

# ── 6. Save JSON ──────────────────────────────────────────────────────────────
os.makedirs("pred_results", exist_ok=True)
out_path = "pred_results/imu_pred.json"
with open(out_path, "w") as fh:
    json.dump(output, fh, indent=2)

print(f"Saved to {out_path}")
print(json.dumps(output, indent=2))
